import{_ as a,o as d,c as o,ag as e}from"./chunks/framework.ePeAWSvT.js";const u=JSON.parse('{"title":"바이브코딩이란?","description":"","frontmatter":{},"headers":[],"relativePath":"학습자료/3-바이브코딩기초/3-1-바이브코딩.md","filePath":"학습자료/3-바이브코딩기초/3-1-바이브코딩.md"}'),s={name:"학습자료/3-바이브코딩기초/3-1-바이브코딩.md"};function r(n,t,l,i,h,p){return d(),o("div",null,[...t[0]||(t[0]=[e(`<h1 id="바이브코딩이란" tabindex="-1">바이브코딩이란? <a class="header-anchor" href="#바이브코딩이란" aria-label="Permalink to &quot;바이브코딩이란?&quot;">​</a></h1><p>코딩을 몰라도 AI에게 &quot;이거 만들어줘&quot;라고 말할 수 있는 시대가 왔습니다.</p><hr><h2 id="바이브코딩이-뭔가요" tabindex="-1">바이브코딩이 뭔가요? <a class="header-anchor" href="#바이브코딩이-뭔가요" aria-label="Permalink to &quot;바이브코딩이 뭔가요?&quot;">​</a></h2><blockquote><p><strong>바이브코딩(Vibe Coding)</strong> = 분위기/느낌으로 코딩을 시키는 것</p></blockquote><p>코드를 직접 쓰는 게 아니라, <strong>자연어(일상 말)로 AI에게 원하는 걸 설명</strong>하면 AI가 코드를 만들어주는 방식입니다.</p><p>2025년 Andrej Karpathy(테슬라 AI 총괄 출신)가 처음 쓴 용어로, &quot;코드를 쓰는 게 아니라 분위기를 전달한다&quot;는 뜻입니다.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>이전: 프로그래밍 언어를 배워서 직접 코드를 작성</span></span>
<span class="line"><span>바이브코딩: &quot;이런 느낌으로 만들어줘&quot;라고 말하면 AI가 코드를 작성</span></span></code></pre></div><hr><h2 id="이전-방식-vs-바이브코딩" tabindex="-1">이전 방식 vs 바이브코딩 <a class="header-anchor" href="#이전-방식-vs-바이브코딩" aria-label="Permalink to &quot;이전 방식 vs 바이브코딩&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>이전 방식</th><th>바이브코딩</th></tr></thead><tbody><tr><td><strong>필요한 것</strong></td><td>프로그래밍 언어 학습 (몇 달~몇 년)</td><td>원하는 걸 말로 설명하는 능력</td></tr><tr><td><strong>작업 방식</strong></td><td>코드를 한 줄씩 직접 작성</td><td>AI에게 자연어로 지시</td></tr><tr><td><strong>오류 대응</strong></td><td>에러 메시지를 읽고 직접 디버깅</td><td>&quot;이거 에러 나는데 고쳐줘&quot;</td></tr><tr><td><strong>진입장벽</strong></td><td>높음 (코딩 교육 필수)</td><td>낮음 (말만 할 줄 알면 됨)</td></tr><tr><td><strong>결과물</strong></td><td>정확하지만 느림</td><td>빠르지만 검수 필요</td></tr><tr><td><strong>비유</strong></td><td>직접 요리하기</td><td>셰프에게 &quot;이런 맛으로 만들어주세요&quot;</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">핵심</p><p>바이브코딩은 <strong>&quot;코딩 실력&quot;이 아니라 &quot;설명 능력&quot;이 중요한 시대</strong>를 의미합니다.</p></div><hr><h2 id="비개발자에게-왜-중요한가" tabindex="-1">비개발자에게 왜 중요한가? <a class="header-anchor" href="#비개발자에게-왜-중요한가" aria-label="Permalink to &quot;비개발자에게 왜 중요한가?&quot;">​</a></h2><h3 id="이전에는-불가능했던-것들" tabindex="-1">이전에는 불가능했던 것들 <a class="header-anchor" href="#이전에는-불가능했던-것들" aria-label="Permalink to &quot;이전에는 불가능했던 것들&quot;">​</a></h3><table tabindex="0"><thead><tr><th>하고 싶은 것</th><th>이전</th><th>바이브코딩 시대</th></tr></thead><tbody><tr><td>간단한 웹페이지 만들기</td><td>외주 맡기거나 코딩 배워야 함</td><td>&quot;이런 페이지 만들어줘&quot;</td></tr><tr><td>엑셀 데이터 자동 분석</td><td>VBA 매크로 학습 필요</td><td>&quot;이 엑셀 분석해서 그래프 만들어줘&quot;</td></tr><tr><td>반복 업무 자동화</td><td>개발자에게 요청 → 대기</td><td>&quot;매주 이 작업 자동으로 해줘&quot;</td></tr><tr><td>업무 도구 커스터마이징</td><td>불가능 (있는 그대로 사용)</td><td>&quot;이 부분을 이렇게 바꿔줘&quot;</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">달라진 점</p><p>코딩을 몰라도 <strong>앱, 자동화, 웹페이지</strong>를 만들 수 있는 시대입니다. 필요한 건 &quot;무엇을 만들고 싶은지&quot; 명확하게 아는 것뿐입니다.</p></div><hr><h2 id="claude-code에서-바이브코딩하는-3가지-도구" tabindex="-1">Claude Code에서 바이브코딩하는 3가지 도구 <a class="header-anchor" href="#claude-code에서-바이브코딩하는-3가지-도구" aria-label="Permalink to &quot;Claude Code에서 바이브코딩하는 3가지 도구&quot;">​</a></h2><p>오늘 워크샵에서 배우는 3가지가 바로 바이브코딩의 핵심 도구입니다.</p><h3 id="_1-스킬-skills-—-이렇게-해줘-를-저장" tabindex="-1">1. 스킬 (Skills) — &quot;이렇게 해줘&quot;를 저장 <a class="header-anchor" href="#_1-스킬-skills-—-이렇게-해줘-를-저장" aria-label="Permalink to &quot;1. 스킬 (Skills) — &quot;이렇게 해줘&quot;를 저장&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>한 번 만들면 → /스킬이름 한 줄로 반복 실행</span></span></code></pre></div><p>매번 같은 설명을 반복할 필요 없이, SKILL.md에 한 번 적어두면 끝. 바이브코딩의 <strong>자동화 엔진</strong>입니다.</p><h3 id="_2-claude-md-—-나는-이런-사람이야-를-기억" tabindex="-1">2. CLAUDE.md — &quot;나는 이런 사람이야&quot;를 기억 <a class="header-anchor" href="#_2-claude-md-—-나는-이런-사람이야-를-기억" aria-label="Permalink to &quot;2. CLAUDE.md — &quot;나는 이런 사람이야&quot;를 기억&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>한 번 써두면 → 모든 대화에서 자동 반영</span></span></code></pre></div><p>AI에게 내 상황, 선호, 규칙을 알려두는 파일. 바이브코딩의 **컨텍스트(맥락)**입니다.</p><h3 id="_3-mcp-—-저것도-연결해줘-로-확장" tabindex="-1">3. MCP — &quot;저것도 연결해줘&quot;로 확장 <a class="header-anchor" href="#_3-mcp-—-저것도-연결해줘-로-확장" aria-label="Permalink to &quot;3. MCP — &quot;저것도 연결해줘&quot;로 확장&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>외부 도구 연결 → AI가 캘린더, 노션, 슬랙까지 직접 조작</span></span></code></pre></div><p>AI의 손발을 늘려주는 연결 포트. 바이브코딩의 <strong>확장 케이블</strong>입니다.</p><hr><h2 id="이번-파트에서-배울-것" tabindex="-1">이번 파트에서 배울 것 <a class="header-anchor" href="#이번-파트에서-배울-것" aria-label="Permalink to &quot;이번 파트에서 배울 것&quot;">​</a></h2><table tabindex="0"><thead><tr><th>순서</th><th>내용</th><th>설명</th></tr></thead><tbody><tr><td><strong>3-1</strong></td><td>바이브코딩 (지금 여기)</td><td>개념과 왜 중요한지</td></tr><tr><td><strong>3-2</strong></td><td><a href="/학습자료/3-바이브코딩기초/3-2-claudemd">CLAUDE.md</a></td><td>AI에게 기억 심어주기</td></tr><tr><td><strong>3-3</strong></td><td><a href="/학습자료/3-바이브코딩기초/3-3-mcp설명">MCP 설명</a></td><td>AI에 외부 도구 연결하는 원리</td></tr><tr><td><strong>3-4</strong></td><td><a href="/학습자료/3-바이브코딩기초/3-4-mcp설치실습">MCP 설치 실습</a></td><td>직접 MCP 설치하고 테스트</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">기억하세요</p><p>바이브코딩 = <strong>말로 시키는 코딩</strong></p><p>그리고 Claude Code는 바이브코딩을 가장 잘 할 수 있는 도구 중 하나입니다. 스킬, CLAUDE.md, MCP — 이 세 가지가 그 이유입니다.</p></div><hr><p><strong><a href="/학습자료/3-바이브코딩기초/3-2-claudemd">CLAUDE.md →</a></strong></p>`,35)])])}const b=a(s,[["render",r]]);export{u as __pageData,b as default};
